xpath.script:
const _products = ;
const _attachments = ;

const _attachmentsByProduct = {};
_attachments.forEach(a => {
    if (!_attachmentsByProduct[a.res_id]) _attachmentsByProduct[a.res_id] = [];
    _attachmentsByProduct[a.res_id].push({ name: a.name, url: a.url });
});

var OdooProductData = _products
    .filter(p => _attachmentsByProduct[p.id])
    .map(p => ({
        sku: p.default_code,
        type: p.x_studio_product_type_for_doc_selector,
        attachments: _attachmentsByProduct[p.id]
    }));
